  1→/**
  2→ * Tests for MCP client detection and configuration
  3→ */
  4→
  5→import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
  6→import * as fs from "fs";
  7→import * as path from "path";
  8→import * as os from "os";
  9→import {
 10→  detectMcpClients,
 11→  addSequantToMcpConfig,
 12→  getSequantMcpConfig,
 13→  createProjectMcpJson,
 14→} from "./mcp-config.js";
 15→
 16→describe("mcp-config", () => {
 17→  describe("getSequantMcpConfig", () => {
 18→    it("should return config with npx command", () => {
 19→      const config = getSequantMcpConfig();
 20→      expect(config.command).toBe("npx");
 21→      expect(config.args).toEqual(["sequant@latest", "serve"]);
 22→    });
 23→
 24→    it("should include cwd for claude-desktop", () => {
 25→      const config = getSequantMcpConfig({
 26→        projectDir: "/my/project",
 27→        clientType: "claude-desktop",
 28→      });
 29→      expect(config.cwd).toBe("/my/project");
 30→    });
 31→
 32→    it("should include cwd for vscode-continue", () => {
 33→      const config = getSequantMcpConfig({
 34→        projectDir: "/my/project",
 35→        clientType: "vscode-continue",
 36→      });
 37→      expect(config.cwd).toBe("/my/project");
 38→    });
 39→
 40→    it("should omit cwd for cursor", () => {
 41→      const config = getSequantMcpConfig({
 42→        projectDir: "/my/project",
 43→        clientType: "cursor",
 44→      });
 45→      expect(config.cwd).toBeUndefined();
 46→    });
 47→
 48→    it("should fall back to process.cwd() when projectDir is omitted for claude-desktop", () => {
 49→      const config = getSequantMcpConfig({
 50→        clientType: "claude-desktop",
 51→      });
 52→      expect(config.cwd).toBe(process.cwd());
 53→    });
 54→
 55→    it("should omit cwd when no clientType is given", () => {
 56→      const config = getSequantMcpConfig({ projectDir: "/my/project" });
 57→      expect(config.cwd).toBeUndefined();
 58→    });
 59→
 60→    describe("env.ANTHROPIC_API_KEY", () => {
 61→      const originalEnv = process.env.ANTHROPIC_API_KEY;
 62→
 63→      afterEach(() => {
 64→        if (originalEnv !== undefined) {
 65→          process.env.ANTHROPIC_API_KEY = originalEnv;
 66→        } else {
 67→          delete process.env.ANTHROPIC_API_KEY;
 68→        }
 69→      });
 70→
 71→      it("should include env when ANTHROPIC_API_KEY is set", () => {
 72→        process.env.ANTHROPIC_API_KEY = "sk-ant-test-key";
 73→        const config = getSequantMcpConfig();
 74→        expect(config.env).toEqual({
 75→          ANTHROPIC_API_KEY: "sk-ant-test-key",
 76→        });
 77→      });
 78→
 79→      it("should omit env when ANTHROPIC_API_KEY is not set", () => {
 80→        delete process.env.ANTHROPIC_API_KEY;
 81→        const config = getSequantMcpConfig();
 82→        expect(config.env).toBeUndefined();
 83→      });
 84→    });
 85→  });
 86→
 87→  describe("detectMcpClients", () => {
 88→    it("should detect Claude Desktop, Cursor, and VS Code clients", () => {
 89→      const clients = detectMcpClients();
 90→      const names = clients.map((c) => c.name);
 91→
 92→      expect(names).toContain("Claude Desktop");
 93→      expect(names).toContain("Cursor");
 94→      expect(names).toContain("VS Code + Continue");
 95→    });
 96→
 97→    it("should have configPath and clientType for each client", () => {
 98→      const clients = detectMcpClients();
 99→      for (const client of clients) {
100→        expect(client.configPath).toBeTruthy();
101→        expect(typeof client.exists).toBe("boolean");
102→        expect(client.clientType).toBeTruthy();
103→      }
104→    });
105→
106→    it("should assign correct clientType to each client", () => {
107→      const clients = detectMcpClients();
108→      const byName = Object.fromEntries(clients.map((c) => [c.name, c]));
109→
110→      expect(byName["Claude Desktop"].clientType).toBe("claude-desktop");
111→      expect(byName["Cursor"].clientType).toBe("cursor");
112→      expect(byName["VS Code + Continue"].clientType).toBe("vscode-continue");
113→    });
114→  });
115→
116→  describe("addSequantToMcpConfig", () => {
117→    const tmpDir = path.join(os.tmpdir(), "sequant-mcp-test-" + Date.now());
118→    const testConfig = path.join(tmpDir, "mcp.json");
119→
120→    beforeEach(() => {
121→      fs.mkdirSync(tmpDir, { recursive: true });
122→    });
123→
124→    afterEach(() => {
125→      fs.rmSync(tmpDir, { recursive: true, force: true });
126→    });
127→
128→    it("should create config file if it does not exist", () => {
129→      const result = addSequantToMcpConfig(testConfig);
130→      expect(result).toBe(true);
131→
132→      const content = JSON.parse(fs.readFileSync(testConfig, "utf-8"));
133→      expect(content.mcpServers.sequant).toBeDefined();
134→      expect(content.mcpServers.sequant.command).toBe("npx");
135→    });
136→
137→    it("should add to existing config without overwriting", () => {
138→      // Create existing config with another server
139→      fs.writeFileSync(
140→        testConfig,
141→        JSON.stringify({
142→          mcpServers: {
143→            other: { command: "node", args: ["other.js"] },
144→          },
145→        }),
146→      );
147→
148→      const result = addSequantToMcpConfig(testConfig);
149→      expect(result).toBe(true);
150→
151→      const content = JSON.parse(fs.readFileSync(testConfig, "utf-8"));
152→      expect(content.mcpServers.other).toBeDefined();
153→      expect(content.mcpServers.sequant).toBeDefined();
154→    });
155→
156→    it("should return false if already configured", () => {
157→      addSequantToMcpConfig(testConfig);
158→      const result = addSequantToMcpConfig(testConfig);
159→      expect(result).toBe(false);
160→    });
161→
162→    it("should handle corrupt config file", () => {
163→      fs.writeFileSync(testConfig, "not json");
164→      const result = addSequantToMcpConfig(testConfig);
165→      expect(result).toBe(true);
166→
167→      const content = JSON.parse(fs.readFileSync(testConfig, "utf-8"));
168→      expect(content.mcpServers.sequant).toBeDefined();
169→    });
170→
171→    it("should include cwd when clientType is claude-desktop", () => {
172→      const result = addSequantToMcpConfig(testConfig, "claude-desktop");
173→      expect(result).toBe(true);
174→
175→      const content = JSON.parse(fs.readFileSync(testConfig, "utf-8"));
176→      expect(content.mcpServers.sequant.cwd).toBe(process.cwd());
177→    });
178→
179→    it("should omit cwd when clientType is cursor", () => {
180→      const result = addSequantToMcpConfig(testConfig, "cursor");
181→      expect(result).toBe(true);
182→
183→      const content = JSON.parse(fs.readFileSync(testConfig, "utf-8"));
184→      expect(content.mcpServers.sequant.cwd).toBeUndefined();
185→    });
186→  });
187→
188→  describe("createProjectMcpJson", () => {
189→    const tmpDir = path.join(
190→      os.tmpdir(),
191→      "sequant-mcp-project-test-" + Date.now(),
192→    );
193→
194→    beforeEach(() => {
195→      fs.mkdirSync(tmpDir, { recursive: true });
196→    });
197→
198→    afterEach(() => {
199→      fs.rmSync(tmpDir, { recursive: true, force: true });
200→    });
201→
202→    it("should create .mcp.json when it does not exist", () => {
203→      const result = createProjectMcpJson(tmpDir);
204→
205→      expect(result).toEqual({ created: true, merged: false, skipped: false });
206→
207→      const content = JSON.parse(
208→        fs.readFileSync(path.join(tmpDir, ".mcp.json"), "utf-8"),
209→      );
210→      expect(content.mcpServers.sequant.command).toBe("npx");
211→      expect(content.mcpServers.sequant.args).toEqual([
212→        "sequant@latest",
213→        "serve",
214→      ]);
215→    });
216→
217→    it("should NOT include cwd or env in .mcp.json config", () => {
218→      createProjectMcpJson(tmpDir);
219→
220→      const content = JSON.parse(
221→        fs.readFileSync(path.join(tmpDir, ".mcp.json"), "utf-8"),
222→      );
223→      expect(content.mcpServers.sequant.cwd).toBeUndefined();
224→      expect(content.mcpServers.sequant.env).toBeUndefined();
225→    });
226→
227→    it("should skip when sequant entry already exists", () => {
228→      const existing = {
229→        mcpServers: {
230→          sequant: { command: "npx", args: ["sequant@latest", "serve"] },
231→        },
232→      };
233→      fs.writeFileSync(
234→        path.join(tmpDir, ".mcp.json"),
235→        JSON.stringify(existing),
236→      );
237→
238→      const result = createProjectMcpJson(tmpDir);
239→
240→      expect(result).toEqual({ created: false, merged: false, skipped: true });
241→    });
242→
243→    it("should merge into existing .mcp.json without sequant entry", () => {
244→      const existing = {
245→        mcpServers: {
246→          "other-server": { command: "node", args: ["server.js"] },
247→        },
248→      };
249→      fs.writeFileSync(
250→        path.join(tmpDir, ".mcp.json"),
251→        JSON.stringify(existing),
252→      );
253→
254→      const result = createProjectMcpJson(tmpDir);
255→
256→      expect(result).toEqual({ created: false, merged: true, skipped: false });
257→
258→      const content = JSON.parse(
259→        fs.readFileSync(path.join(tmpDir, ".mcp.json"), "utf-8"),
260→      );
261→      // Existing server preserved
262→      expect(content.mcpServers["other-server"]).toEqual({
263→        command: "node",
264→        args: ["server.js"],
265→      });
266→      // Sequant added
267→      expect(content.mcpServers.sequant.command).toBe("npx");
268→    });
269→
270→    it("should handle corrupt .mcp.json gracefully", () => {
271→      fs.writeFileSync(path.join(tmpDir, ".mcp.json"), "not valid json{{{");
272→
273→      const result = createProjectMcpJson(tmpDir);
274→
275→      expect(result).toEqual({ created: false, merged: true, skipped: false });
276→
277→      const content = JSON.parse(
278→        fs.readFileSync(path.join(tmpDir, ".mcp.json"), "utf-8"),
